+export function evaluateRule(
+  rule: SafetyRule,
+  operation: SafetyOperation,
+): RuleEvaluationResult {
+  if (!rule.enabled) {
+    return {
+      rule,
+      matched: false,
+      action: "allow",
+      message: "",
+    };
+  }
+
+  // Check category match
+  if (rule.category !== operation.type) {
+    return {
+      rule,
+      matched: false,
+      action: "allow",
+      message: "",
+    };
+  }
+
+  // Evaluate conditions
+  let matched: boolean;
+  if (rule.conditionLogic === "and") {
+    matched = rule.conditions.every((cond) => evaluateCondition(cond, operation));
+  } else {
+    matched = rule.conditions.some((cond) => evaluateCondition(cond, operation));
+  }
+
+  return {
+    rule,
+    matched,
+    action: matched ? rule.action : "allow",
+    message: matched ? rule.message : "",
+    alternatives: matched ? rule.alternatives : undefined,
+  };
