+      medium: 0,
+      high: 0,
+      critical: 0,
+    },
+    byAction: {
+      allow: 0,
+      deny: 0,
+      warn: 0,
+      approve: 0,
+    },
+  };
+
+  for (const rule of rules) {
+    if (rule.enabled) {
+      stats.enabledRules++;
+    } else {
+      stats.disabledRules++;
+    }
+    stats.byCategory[rule.category]++;
+    stats.bySeverity[rule.severity]++;
+    stats.byAction[rule.action]++;
+  }
+
+  return stats;
