+// ============================================================================
+// Emergency Controls
+// ============================================================================
+
+/**
+ * Emergency kill switch - immediately disable all agent operations.
+ */
+export async function emergencyStop(
+  workspaceId: string,
+  reason: string,
+  initiatedBy: string,
+): Promise<void> {
+  const config = await getConfig(workspaceId);
+
+  // Disable all safety (which blocks everything by default)
+  config.enabled = true;
+
+  // Add deny-all rule
+  const denyAllRule: SafetyRule = {
+    id: generateId("rule"),
+    name: "Emergency Stop",
+    description: `Emergency stop initiated by ${initiatedBy}: ${reason}`,
+    category: "execution",
+    conditions: [
+      { field: "command", patternType: "glob", pattern: "*" },
+    ],
+    conditionLogic: "and",
+    action: "deny",
+    severity: "critical",
+    message: `Emergency stop active: ${reason}`,
+    enabled: true,
+  };
+
+  config.categories.execution.rules.unshift(denyAllRule);
+  config.categories.filesystem.rules.unshift({
+    ...denyAllRule,
+    id: generateId("rule"),
+    category: "filesystem",
+  });
+  config.categories.git.rules.unshift({
+    ...denyAllRule,
+    id: generateId("rule"),
+    category: "git",
+  });
+  config.categories.network.rules.unshift({
+    ...denyAllRule,
+    id: generateId("rule"),
+    category: "network",
+  });
+
+  config.updatedAt = new Date();
+  configs.set(workspaceId, config);
+
+  logger.warn(
+    {
+      workspaceId,
+      reason,
+      initiatedBy,
+    },
+    "Emergency stop activated",
+  );
+}
+
+/**
+ * Clear emergency stop state.
+ */
+export async function clearEmergencyStop(
+  workspaceId: string,
+  clearedBy: string,
+): Promise<void> {
+  const config = await getConfig(workspaceId);
+
+  // Remove emergency stop rules
+  for (const category of Object.values(config.categories)) {
+    category.rules = category.rules.filter(
+      (r) => r.name !== "Emergency Stop",
+    );
+  }
+
+  config.updatedAt = new Date();
+  configs.set(workspaceId, config);
+
+  logger.info(
+    {
+      workspaceId,
+      clearedBy,
+    },
+    "Emergency stop cleared",
+  );
+}
